239	    @Override
240	    public List<Entity> findStuckEntities(Duration staleThreshold, int maxCount) {
241	        Instant before = Instant.now().minus(staleThreshold);
242	        var pageable = PageRequest.of(0, maxCount);
243	
244	        Page<Entity> page = entityRepository.findStuckEntities(before, pageable);
245	        List<Entity> result = page.getContent();
246	        if (!result.isEmpty()) {
247	            log.info("findStuckEntities: found {} candidates before={}, threshold={}",
248	                    result.size(), before, staleThreshold);
249	        }
250	        return result;
251	    }
252	
253	    // Mark entities that need reprocessing to INIT in batches, and return total updated rows.
254	    @Override
255	    public MarkForReprocessResult markAllForReprocess() {
256	        int totalUpdated = 0;
257	        int failedBatches = 0;
258	        int failedCount = 0;
259	        String runResult = "success";
260	        Timer.Sample runSample = Timer.start(meterRegistry);
261	
262	        try {
263	            int effectiveBatchSize = Math.max(1, markInitBatchSize);
264	            Pageable pageable = PageRequest.of(0, effectiveBatchSize);
265	
266	            // Requirement: one transaction per update batch to avoid a huge long transaction.
267	            TransactionTemplate batchTx = new TransactionTemplate(transactionManager);
268	            // Always use a new transaction here so each batch update is independent:
269	            // if one batch fails, only that batch rolls back and already committed batches stay committed.
270	            batchTx.setPropagationBehavior(TransactionDefinition.PROPAGATION_REQUIRES_NEW);
271	
272	            long lastId = Long.MIN_VALUE;
273	            while (true) {
274	                List<Long> batchIds = entityRepository.findTopNIdsNeedMarkForReprocess(
275	                        lastId, ReprocessState.INIT, pageable);
276	                if (batchIds.isEmpty()) {
277	                    break;
278	                }
279	
280	                try {
281	                    Integer updated = batchTx.execute(status ->
282	                            entityRepository.markBatchForReprocess(batchIds, ReprocessState.INIT));
283	                    int updatedRows = updated == null ? 0 : updated;
284	                    totalUpdated += updatedRows;
285	                } catch (Exception ex) {
286	                    failedBatches++;
287	                    failedCount += batchIds.size();
288	                    log.error(
289	                            "markAllForReprocess: batch update failed for id range [{} - {}], batchSize={}, continue with next batch",
290	                            batchIds.get(0), batchIds.get(batchIds.size() - 1), batchIds.size(), ex
291	                    );
292	                }
293	
294	                // Move the cursor forward even when one batch fails, to avoid getting stuck retrying the same batch.
295	                lastId = batchIds.get(batchIds.size() - 1);
296	
297	                // Last short page means this run has drained current backlog.
298	                if (batchIds.size() < effectiveBatchSize) {
299	                    break;
300	                }
301	            }
302	
303	            if (failedBatches > 0) {
304	                runResult = "partial_failure";
305	                log.warn("markAllForReprocess: completed with partial failures, updatedCount={}, failedBatches={}",
306	                        totalUpdated, failedBatches);
307	            }
308	            return MarkForReprocessResult.builder()
309	                    .updatedCount(totalUpdated)
310	                    .failedBatches(failedBatches)
311	                    .failedCount(failedCount)
312	                    .build();
313	        } catch (Exception ex) {
314	            runResult = "failed";
315	            log.error("markAllForReprocess: failed unexpectedly, updatedCount={}, failedBatches={}",
316	                    totalUpdated, failedBatches, ex);
317	            throw ex;
318	        } finally {
319	            markInitLastFailedBatches.set(failedBatches);
320	            runSample.stop(markInitRunTimeCost(runResult));
321	        }
322	    }
323	
